'use client';

import { useAppContext } from '@/context/AppContext';
import MessageModal from './MessageModal';
export default function LostConnectionModal() {
  const {
    context
  } = useAppContext();
  const {
    isOnline
  } = context;
  const {
    screenRatio
  } = context.deviceRotation ?? {
    screenRatio: 1
  };
  return <div data-sentry-component="LostConnectionModal" data-sentry-source-file="LostConnectionModal.tsx">
      {!isOnline && <MessageModal screenRatio={screenRatio} title={'Internet connection lost. Reconnecting...'} />}
    </div>;
}